  ('optician-moex-01383', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式隱形眼鏡驗配戴鏡驗光的評估，下列敘述何者錯誤？', '["硬式隱形眼鏡驗配戴鏡驗光，有助於鏡片屈光度的確定", "鏡片配戴越陡峭時，為了補償較大的淚鏡，將需要更多的負度數", "鏡片配戴時，變動的視覺並不表示鏡片偏心或是平坦的驗配", "後光學區曲率半徑BOZR每0.05mm的變化，backvertexpower（BVP）需改變0.25D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
